/* This program asks for student's info and 10 marks or until user enters -1
   using loops, and prints all data and average mark
   Author: Leila            V5.0 */
#include <stdio.h>
#define MAX 10
#include <stdbool.h>
int main(void)
{
    char fname[50];
    char lname[50];
    char studentID[10];
	int age;
	int mark[MAX];
    int sum = 0;
    int ret;
    int num_marks = 0;
    printf("What is your first name? ");
    scanf("%s", fname);
    printf("What is your last name? ");
    scanf("%s", lname);
    printf("What is your ID number? ");
    scanf("%s", studentID);

    while(true)
    {
        printf("What is your age? ");
        ret = scanf(" %d", &age);
        for ( int c; c = getchar(), c != '\n' && c != EOF; ); // To clear input
        if (ret == 1 && age>0)
            break;
        else
        {
            printf("Invalid input!\n");
        }
    }

    num_marks = MAX;

    for (int i=0; i<MAX; i++)
    {
        while(true)
        {

            printf("Enter mark %d (or -1 to terminate): ", i + 1);
            ret = scanf("%d", &mark[i]);
            //setbuf(stdin,NULL);
            for ( int c; c = getchar(), c != '\n' && c != EOF; ); // To clear input
            if (ret != 1)
            {
                printf("Invalid input!\n");

            }
            else if(mark[i] < -1 || mark[i] > 100)
                printf("Invalid input!\n");
            else break;

        }
        if (mark[i] == -1){
            num_marks = i;
            break;
        }
    }



	printf("First name: %s\n", fname);
	printf("Last name: %s\n", lname);
	printf("ID: %s\n", studentID);
	printf("Age: %d\n", age);

    for(int i=0; i<num_marks; i++)
    {
        printf("Mark %d: %d\n", i+1, mark[i]);
        sum = sum + mark[i];
    }

    if (num_marks !=0) printf("Average: %.1f\n", (float)sum/num_marks);

    return 0;
}
